import csv
import os
from typing import List, Dict, Any

import modal

app = modal.App("etl-pipeline-orchestrator")

volume = modal.Volume.from_name("etl-pipeline-orchestrator-vol", create_if_missing=True)
secret = modal.Secret.from_name("etl-pipeline-orchestrator-secret")
output_dict = modal.Dict.from_name("etl-pipeline-orchestrator-output", create_if_missing=True)

OUTPUT_PATH = "/data/output.csv"


@app.cls(volumes={"/data": volume}, secrets=[secret])
class ETLPipeline:
    @modal.enter()
    def setup(self) -> None:
        self.db_url = os.environ.get("DB_URL", "")
        self.api_token = os.environ.get("API_TOKEN", "")
        self.output_path = OUTPUT_PATH

    def extract(self) -> List[Dict[str, Any]]:
        data = [
            {"id": 1, "name": "alpha"},
            {"id": 2, "name": "bravo"},
            {"id": 3, "name": "charlie"},
        ]
        return data

    def transform(self, data: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return [{"id": row["id"], "name": row["name"].upper()} for row in data]

    def load(self, data: List[Dict[str, Any]]) -> int:
        os.makedirs(os.path.dirname(self.output_path), exist_ok=True)
        with open(self.output_path, "w", newline="") as handle:
            writer = csv.DictWriter(handle, fieldnames=["id", "name"])
            writer.writeheader()
            writer.writerows(data)
        volume.commit()
        return len(data)

    @modal.method()
    def run(self) -> Dict[str, Any]:
        try:
            extracted = self.extract()
            transformed = self.transform(extracted)
            loaded_count = self.load(transformed)
            return {
                "records_extracted": len(extracted),
                "records_loaded": loaded_count,
                "pipeline_status": "success",
                "output_path": self.output_path,
            }
        except Exception as exc:
            return {
                "records_extracted": 0,
                "records_loaded": 0,
                "pipeline_status": f"failed: {exc}",
                "output_path": self.output_path,
            }


@app.function(schedule=modal.Period(hours=1))
def scheduled_etl() -> Dict[str, Any]:
    pipeline = ETLPipeline()
    return pipeline.run.remote()


@app.local_entrypoint()
def main() -> None:
    pipeline = ETLPipeline()
    result = pipeline.run.remote()
    output_dict["records_extracted"] = result["records_extracted"]
    output_dict["records_loaded"] = result["records_loaded"]
    output_dict["pipeline_status"] = result["pipeline_status"]
    output_dict["output_path"] = result["output_path"]
    print("Stored ETL results in Modal Dict:", result)
